={{
  (() => {
    const s = String($json.qv_status ?? '').toLowerCase();
    const d = ($json.deliverable ?? $json.data?.deliverable);
    if (d === true) return 0;
    if (s === 'valid' || s === 'deliverable' || s === 'delivered' || s === 'ok') return 0;
    if (s.includes('deliverable')) return 0;
    return 1;
  })()
}}
